SET NOCOUNT ON;

------------------------------------------------------------
-- EDIT THESE
------------------------------------------------------------
DECLARE @migration_root NVARCHAR(4000);
DECLARE @work_schema NVARCHAR(128);
DECLARE @data_source NVARCHAR(128);
DECLARE @file_format NVARCHAR(128);

SET @migration_root = N'synapse-migration/run_2026_04_08';
SET @work_schema    = N'_mig';
SET @data_source    = N'target_adls';
SET @file_format    = N'_mig_parquet_format';

------------------------------------------------------------
-- GENERAL VARIABLES
------------------------------------------------------------
DECLARE @sql NVARCHAR(MAX);
DECLARE @work_schema_q NVARCHAR(300);
DECLARE @data_source_q NVARCHAR(300);
DECLARE @file_format_q NVARCHAR(300);

DECLARE @schema_name NVARCHAR(128);
DECLARE @table_name NVARCHAR(128);
DECLARE @distribution_policy NVARCHAR(60);
DECLARE @distribution_column NVARCHAR(128);
DECLARE @target_index_type NVARCHAR(60);
DECLARE @clustered_index_column NVARCHAR(128);
DECLARE @data_location NVARCHAR(4000);

DECLARE @schema_q NVARCHAR(300);
DECLARE @table_q NVARCHAR(300);
DECLARE @temp_ext_name NVARCHAR(128);
DECLARE @temp_ext_q NVARCHAR(300);

DECLARE @cols_ddl NVARCHAR(MAX);
DECLARE @cols_only NVARCHAR(MAX);
DECLARE @first_col_q NVARCHAR(300);
DECLARE @col_name NVARCHAR(128);
DECLARE @type_name NVARCHAR(128);
DECLARE @max_length INT;
DECLARE @precision_value INT;
DECLARE @scale_value INT;
DECLARE @is_nullable BIT;
DECLARE @collation_name NVARCHAR(128);
DECLARE @column_id INT;
DECLARE @col_def NVARCHAR(MAX);

DECLARE @i INT;
DECLARE @imax INT;
DECLARE @j INT;
DECLARE @jmax INT;

SET @work_schema_q = N'[' + @work_schema + N']';
SET @data_source_q = N'[' + @data_source + N']';
SET @file_format_q = N'[' + @file_format + N']';

------------------------------------------------------------
-- PREP OBJECTS
------------------------------------------------------------
IF NOT EXISTS
(
    SELECT 1
    FROM sys.schemas
    WHERE name = @work_schema
)
BEGIN
    SET @sql = N'CREATE SCHEMA ' + @work_schema_q + N';';
    EXEC(@sql);
END;

IF NOT EXISTS
(
    SELECT 1
    FROM sys.external_file_formats
    WHERE name = @file_format
)
BEGIN
    SET @sql = N'
    CREATE EXTERNAL FILE FORMAT ' + @file_format_q + N'
    WITH
    (
        FORMAT_TYPE = PARQUET
    );';
    EXEC(@sql);
END;

------------------------------------------------------------
-- DROP OLD READERS / STAGING TABLES
------------------------------------------------------------
IF EXISTS
(
    SELECT 1
    FROM sys.external_tables t
    JOIN sys.schemas s
      ON s.schema_id = t.schema_id
    WHERE s.name = @work_schema
      AND t.name = N'manifest_tables_ext'
)
BEGIN
    SET @sql = N'DROP EXTERNAL TABLE ' + @work_schema_q + N'.[manifest_tables_ext];';
    EXEC(@sql);
END;

IF EXISTS
(
    SELECT 1
    FROM sys.external_tables t
    JOIN sys.schemas s
      ON s.schema_id = t.schema_id
    WHERE s.name = @work_schema
      AND t.name = N'manifest_columns_ext'
)
BEGIN
    SET @sql = N'DROP EXTERNAL TABLE ' + @work_schema_q + N'.[manifest_columns_ext];';
    EXEC(@sql);
END;

IF EXISTS
(
    SELECT 1
    FROM sys.tables t
    JOIN sys.schemas s
      ON s.schema_id = t.schema_id
    WHERE s.name = @work_schema
      AND t.name = N'manifest_tables'
)
BEGIN
    SET @sql = N'DROP TABLE ' + @work_schema_q + N'.[manifest_tables];';
    EXEC(@sql);
END;

IF EXISTS
(
    SELECT 1
    FROM sys.tables t
    JOIN sys.schemas s
      ON s.schema_id = t.schema_id
    WHERE s.name = @work_schema
      AND t.name = N'manifest_columns'
)
BEGIN
    SET @sql = N'DROP TABLE ' + @work_schema_q + N'.[manifest_columns];';
    EXEC(@sql);
END;

------------------------------------------------------------
-- READ MANIFESTS FROM ADLS
------------------------------------------------------------
SET @sql = N'
CREATE EXTERNAL TABLE ' + @work_schema_q + N'.[manifest_tables_ext]
(
    schema_name            NVARCHAR(128),
    table_name             NVARCHAR(128),
    source_object_type     NVARCHAR(20),
    distribution_policy    NVARCHAR(60),
    distribution_column    NVARCHAR(128),
    target_index_type      NVARCHAR(60),
    clustered_index_column NVARCHAR(128),
    data_location          NVARCHAR(4000)
)
WITH
(
    LOCATION = ''' + @migration_root + N'/manifest/tables/'',
    DATA_SOURCE = ' + @data_source_q + N',
    FILE_FORMAT = ' + @file_format_q + N'
);';
EXEC(@sql);

SET @sql = N'
CREATE EXTERNAL TABLE ' + @work_schema_q + N'.[manifest_columns_ext]
(
    schema_name      NVARCHAR(128),
    table_name       NVARCHAR(128),
    column_id        INT,
    column_name      NVARCHAR(128),
    type_name        NVARCHAR(128),
    max_length       INT,
    precision_value  INT,
    scale_value      INT,
    is_nullable      BIT,
    collation_name   NVARCHAR(128)
)
WITH
(
    LOCATION = ''' + @migration_root + N'/manifest/columns/'',
    DATA_SOURCE = ' + @data_source_q + N',
    FILE_FORMAT = ' + @file_format_q + N'
);';
EXEC(@sql);

------------------------------------------------------------
-- STAGE MANIFESTS LOCALLY
------------------------------------------------------------
SET @sql = N'
CREATE TABLE ' + @work_schema_q + N'.[manifest_tables]
WITH
(
    DISTRIBUTION = ROUND_ROBIN,
    HEAP
)
AS
SELECT *
FROM ' + @work_schema_q + N'.[manifest_tables_ext];';
EXEC(@sql);

SET @sql = N'
CREATE TABLE ' + @work_schema_q + N'.[manifest_columns]
WITH
(
    DISTRIBUTION = ROUND_ROBIN,
    HEAP
)
AS
SELECT *
FROM ' + @work_schema_q + N'.[manifest_columns_ext];';
EXEC(@sql);

------------------------------------------------------------
-- OBJECT LOOP LIST
------------------------------------------------------------
IF OBJECT_ID('tempdb..#object_list') IS NOT NULL DROP TABLE #object_list;

CREATE TABLE #object_list
(
    rn                     INT            NOT NULL,
    schema_name            NVARCHAR(128)  NOT NULL,
    table_name             NVARCHAR(128)  NOT NULL,
    distribution_policy    NVARCHAR(60)   NULL,
    distribution_column    NVARCHAR(128)  NULL,
    target_index_type      NVARCHAR(60)   NOT NULL,
    clustered_index_column NVARCHAR(128)  NULL,
    data_location          NVARCHAR(4000) NOT NULL
)
WITH
(
    DISTRIBUTION = ROUND_ROBIN,
    HEAP
);

INSERT INTO #object_list
(
    rn,
    schema_name,
    table_name,
    distribution_policy,
    distribution_column,
    target_index_type,
    clustered_index_column,
    data_location
)
SELECT
    ROW_NUMBER() OVER (ORDER BY schema_name, table_name),
    schema_name,
    table_name,
    distribution_policy,
    distribution_column,
    target_index_type,
    clustered_index_column,
    data_location
FROM [_mig].[manifest_tables];

SELECT @i = 1, @imax = MAX(rn) FROM #object_list;

WHILE @i <= @imax
BEGIN
    SELECT
        @schema_name = schema_name,
        @table_name = table_name,
        @distribution_policy = distribution_policy,
        @distribution_column = distribution_column,
        @target_index_type = target_index_type,
        @clustered_index_column = clustered_index_column,
        @data_location = data_location
    FROM #object_list
    WHERE rn = @i;

    SET @schema_q = N'[' + @schema_name + N']';
    SET @table_q  = N'[' + @table_name + N']';
    SET @temp_ext_name = N'ext_' + CAST(@i AS NVARCHAR(20));
    SET @temp_ext_q    = N'[' + @temp_ext_name + N']';

    IF NOT EXISTS
    (
        SELECT 1
        FROM sys.schemas
        WHERE name = @schema_name
    )
    BEGIN
        SET @sql = N'CREATE SCHEMA ' + @schema_q + N';';
        EXEC(@sql);
    END;

    --------------------------------------------------------
    -- BUILD COLUMN DDL IN ORDER
    --------------------------------------------------------
    IF OBJECT_ID('tempdb..#col_list') IS NOT NULL DROP TABLE #col_list;

    CREATE TABLE #col_list
    (
        rn              INT           NOT NULL,
        column_id       INT           NOT NULL,
        column_name     NVARCHAR(128) NOT NULL,
        type_name       NVARCHAR(128) NOT NULL,
        max_length      INT           NULL,
        precision_value INT           NULL,
        scale_value     INT           NULL,
        is_nullable     BIT           NOT NULL,
        collation_name  NVARCHAR(128) NULL
    )
    WITH
    (
        DISTRIBUTION = ROUND_ROBIN,
        HEAP
    );

    INSERT INTO #col_list
    (
        rn,
        column_id,
        column_name,
        type_name,
        max_length,
        precision_value,
        scale_value,
        is_nullable,
        collation_name
    )
    SELECT
        ROW_NUMBER() OVER (ORDER BY column_id),
        column_id,
        column_name,
        type_name,
        max_length,
        precision_value,
        scale_value,
        is_nullable,
        collation_name
    FROM [_mig].[manifest_columns]
    WHERE schema_name = @schema_name
      AND table_name = @table_name;

    SET @cols_ddl = N'';
    SET @cols_only = N'';
    SET @first_col_q = NULL;

    SELECT @j = 1, @jmax = MAX(rn) FROM #col_list;

    WHILE @j <= @jmax
    BEGIN
        SELECT
            @column_id = column_id,
            @col_name = column_name,
            @type_name = type_name,
            @max_length = max_length,
            @precision_value = precision_value,
            @scale_value = scale_value,
            @is_nullable = is_nullable,
            @collation_name = collation_name
        FROM #col_list
        WHERE rn = @j;

        SET @col_def = N'[' + @col_name + N'] ';

        IF @type_name IN (N'varchar', N'char', N'varbinary', N'binary')
            SET @col_def = @col_def + @type_name + N'(' + CASE WHEN @max_length = -1 THEN N'MAX' ELSE CAST(@max_length AS NVARCHAR(20)) END + N')';
        ELSE IF @type_name IN (N'nvarchar', N'nchar')
            SET @col_def = @col_def + @type_name + N'(' + CASE WHEN @max_length = -1 THEN N'MAX' ELSE CAST(@max_length / 2 AS NVARCHAR(20)) END + N')';
        ELSE IF @type_name IN (N'decimal', N'numeric')
            SET @col_def = @col_def + @type_name + N'(' + CAST(@precision_value AS NVARCHAR(20)) + N',' + CAST(@scale_value AS NVARCHAR(20)) + N')';
        ELSE IF @type_name IN (N'datetime2', N'time', N'datetimeoffset')
            SET @col_def = @col_def + @type_name + N'(' + CAST(@scale_value AS NVARCHAR(20)) + N')';
        ELSE
            SET @col_def = @col_def + @type_name;

        IF @collation_name IS NOT NULL
           AND @type_name IN (N'varchar', N'char', N'nvarchar', N'nchar')
            SET @col_def = @col_def + N' COLLATE ' + @collation_name;

        IF @is_nullable = 1
            SET @col_def = @col_def + N' NULL';
        ELSE
            SET @col_def = @col_def + N' NOT NULL';

        IF LEN(@cols_ddl) > 0
            SET @cols_ddl = @cols_ddl + N',' + CHAR(10);
        SET @cols_ddl = @cols_ddl + @col_def;

        IF LEN(@cols_only) > 0
            SET @cols_only = @cols_only + N',' + CHAR(10);
        SET @cols_only = @cols_only + N'[' + @col_name + N']';

        IF @first_col_q IS NULL
            SET @first_col_q = N'[' + @col_name + N']';

        SET @j = @j + 1;
    END;

    --------------------------------------------------------
    -- DROP EXISTING TARGET OBJECTS OF SAME NAME
    --------------------------------------------------------
    IF EXISTS
    (
        SELECT 1
        FROM sys.tables t
        JOIN sys.schemas s
          ON s.schema_id = t.schema_id
        WHERE s.name = @schema_name
          AND t.name = @table_name
    )
    BEGIN
        SET @sql = N'DROP TABLE ' + @schema_q + N'.' + @table_q + N';';
        EXEC(@sql);
    END;

    IF EXISTS
    (
        SELECT 1
        FROM sys.external_tables t
        JOIN sys.schemas s
          ON s.schema_id = t.schema_id
        WHERE s.name = @schema_name
          AND t.name = @table_name
    )
    BEGIN
        SET @sql = N'DROP EXTERNAL TABLE ' + @schema_q + N'.' + @table_q + N';';
        EXEC(@sql);
    END;

    IF EXISTS
    (
        SELECT 1
        FROM sys.external_tables t
        JOIN sys.schemas s
          ON s.schema_id = t.schema_id
        WHERE s.name = @work_schema
          AND t.name = @temp_ext_name
    )
    BEGIN
        SET @sql = N'DROP EXTERNAL TABLE ' + @work_schema_q + N'.' + @temp_ext_q + N';';
        EXEC(@sql);
    END;

    --------------------------------------------------------
    -- CREATE TEMP EXTERNAL TABLE OVER EXPORTED PARQUET
    --------------------------------------------------------
    SET @sql = N'
    CREATE EXTERNAL TABLE ' + @work_schema_q + N'.' + @temp_ext_q + N'
    (
' + @cols_ddl + N'
    )
    WITH
    (
        LOCATION = ''' + @data_location + N''',
        DATA_SOURCE = ' + @data_source_q + N',
        FILE_FORMAT = ' + @file_format_q + N'
    );';
    EXEC(@sql);

    --------------------------------------------------------
    -- CREATE TARGET INTERNAL TABLE
    --------------------------------------------------------
    SET @sql = N'
    CREATE TABLE ' + @schema_q + N'.' + @table_q + N'
    (
' + @cols_ddl + N'
    )
    WITH
    (
        DISTRIBUTION = ' +
        CASE
            WHEN @distribution_policy = N'HASH' AND @distribution_column IS NOT NULL
                THEN N'HASH([' + @distribution_column + N'])'
            WHEN @distribution_policy = N'REPLICATE'
                THEN N'REPLICATE'
            ELSE N'ROUND_ROBIN'
        END + N',
        ' +
        CASE
            WHEN @target_index_type = N'HEAP'
                THEN N'HEAP'
            WHEN @target_index_type = N'CLUSTERED INDEX' AND @clustered_index_column IS NOT NULL
                THEN N'CLUSTERED INDEX ([' + @clustered_index_column + N'])'
            ELSE N'CLUSTERED COLUMNSTORE INDEX'
        END + N'
    );';
    EXEC(@sql);

    --------------------------------------------------------
    -- LOAD DATA
    --------------------------------------------------------
    SET @sql = N'
    INSERT INTO ' + @schema_q + N'.' + @table_q + N'
    (
' + @cols_only + N'
    )
    SELECT
' + @cols_only + N'
    FROM ' + @work_schema_q + N'.' + @temp_ext_q + N';';
    EXEC(@sql);

    SET @sql = N'DROP EXTERNAL TABLE ' + @work_schema_q + N'.' + @temp_ext_q + N';';
    EXEC(@sql);

    PRINT N'Imported ' + @schema_q + N'.' + @table_q;

    SET @i = @i + 1;
END;

PRINT N'Import complete';
